export interface Product {
    id: string
    sku: string
    name: string
    description: string
    category: string
    subcategory: string
    basePrice: number | null
    colors: string[]
    materials: string[]
    dimensions: string
    minOrderQuantity: number | null
    image: string
    images: string[]
    brandingZones: BrandingZone[]
    availableTechniques: string[]
    featured?: boolean
    new?: boolean
    onSale?: boolean
    salePrice?: number | null
    searchTags?: string[]
}

export interface BrandingZone {
    id: string
    name: string
    dimensions: string
    maxColors: number
}

export interface Category {
    id: string
    name: string
    slug: string
    icon: string
    productCount: number
    image: string
}

export interface Technique {
    id: string
    name: string
    description: string
    priceModifier: number
}

export interface Testimonial {
    id: string
    name: string
    role: string
    company: string
    content: string
    rating: number
    image: string
}

export interface Promotion {
    id: string
    title: string
    description: string
    code: string
    validUntil: string
    type: string
    value: number
}

export interface TrustStat {
    value: string
    label: string
}

